import "./App.css";
import YoutubeData from "./Components/YoutubeData";

const YoutubeItem = (props) => {
  // console.log(props);

  return (
    <div className="">
      <div className="youtube-item">
        <div className="youtube-image" style={{ height: "250px" }}>
          <img
            className="youtube-bg"
            src={props.image}
            alt=""
            // style={{ display: "block", maxWidth: "100%", width: "100%", height:"100%"}}
          />
        </div>
        <div className="youtube-footer">
          <img src={props.image2} alt="youtube-avt" className="youtube-avt" />
          <div className="youtube-info">
            <h3 className="youtube-title">
              {props.title || "This is title h3"}
            </h3>
            <h4 className="youtube-author">
              {props.author || "This is example of author name"}
            </h4>
          </div>
        </div>
      </div>
    </div>
  );
};
console.log(">>>YoutubeData:", YoutubeData);
//parent component
const App = () => {
  const array = [1, 2, 3, 4, 5];
  const double = array.map((item) => {
    return item * 2;
  });
  console.log(double);

  return (
    <div className="">
      <h1>Less12</h1>
      <div className="youtube-list">
        {YoutubeData.map((item) => (
          <YoutubeItem
            key={item.id}
            image={item.image}
            image2={item.image2}
            title={item.title}
            author={item.author}
          />
        ))}
        {/* {YoutubeData.map((item, index) => {
          return <div>Hello {index + 1}</div>;
        })} */}
      </div>
    </div>
  );
};

export default App;
